definition.script:
pipeline {
    agent any

    environment {
        DOCKER_IMAGE = "anasseraoui/shopping-cart"
        DOCKER_TAG = "latest"
        ANSIBLE_HOST_KEY_CHECKING = 'False'
        // Had l-lign ghadi t-bypassi biha l-mouchkil dyal known_hosts tqaniyan
        ANSIBLE_SSH_ARGS = '-o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null'
    }

    stages {

        stage('Git Checkout') {
            steps {
                git branch: 'main',
                    credentialsId: 'github-tokens',
                    url: 'https://github.com/anasseraoui-oss/Shopping-cart.git'
            }
        }

        stage('Compile') {
            steps {
                sh 'mvn clean compile -DskipTests=true'
            }
        }

        stage('OWASP Scan') {
            steps {
                catchError(buildResult: 'SUCCESS', stageResult: 'FAILURE') {
                    withCredentials([string(credentialsId: 'NVD_API_KEY', variable: 'NVD_API_KEY')]) {
                        dependencyCheck(
                            additionalArguments: """
                                --scan ./
                                --format XML
                                --format HTML
                                --out ./dependency-check-report
                                --nvdApiKey ${NVD_API_KEY}
                            """,
                            odcInstallation: 'DP'
                        )
                    }
                    dependencyCheckPublisher pattern: '**/dependency-check-report.xml'
                }
            }
        }

        stage('SonarQube Analysis') {
            environment {
                SONAR_AUTH = credentials('SONAR_TOKEN') 
            }
            steps {
                withSonarQubeEnv('sonar-server') {
                    // Utilisation de la version explicite du plugin pour Ã©viter le warning
                    sh '''mvn org.sonarsource.scanner.maven:sonar-maven-plugin:4.0.0.4121:sonar \
                    -Dsonar.projectName=Shopping-cart \
                    -Dsonar.projectKey=Shopping-cart \
                    -Dsonar.login=${SONAR_AUTH}'''
                }
            }
        }

        stage('Build') {
            steps {
                sh 'mvn clean package -DskipTests=true'
            }
        }

        stage('Docker Build & Push') {
            steps {
                script {
                    withCredentials([usernamePassword(credentialsId: 'docker-credentials', passwordVariable: 'DOCKER_PASSWORD', usernameVariable: 'DOCKER_USERNAME')]) {
                        sh 'echo "$DOCKER_PASSWORD" | docker login -u "$DOCKER_USERNAME" --password-stdin'
                        sh "docker build -t ${DOCKER_IMAGE}:${DOCKER_TAG} ."
                        sh "docker push ${DOCKER_IMAGE}:${DOCKER_TAG}"
                        sh 'docker logout'
                    }
                }
            }
        }

        stage('Ansible Preparation') {
            steps {
                script {
                    // Connexion au rÃ©seau et PrÃ©paration Python
                    echo "ð Connecting Jenkins container to ansible-network..."
                    sh "docker network connect ansible-network \$(hostname) || true"
                    echo "ð Installing python3 on target node (ansible-node1) for Ansible..."
                    sh "docker exec -u 0 ansible-node1 sh -c 'apt-get update && apt-get install -y python3 || apk add --no-cache python3'"
                }
            }
        }
        stage('Ansible Deploy') {
            steps {
                ansiblePlaybook(
                    playbook: 'ansible/deploy.yml',
                    inventory: 'inventory.ini',
                    credentialsId: 'ansible-ssh',
                    become: false,
                    colorized: true
                )
            }
        }
        stage('Health Check') {
            steps {
                script {
                    echo 'â³ Attente du dÃ©marrage de Spring Boot (Polling sur 100s)...'
                    def isReady = false
                    for (int i = 0; i < 10; i++) {
                        sleep(10)
                        def status = sh(
                            script: "docker exec ansible-node1 curl -s -L -o /dev/null -w '%{http_code}' http://shopping-cart:8070/health || echo '000'",
                            returnStdout: true
                        ).trim()
                        echo "ð Tentative ${i+1}/10 - Code HTTP : ${status}"
                        if (status == '200') { 
                            isReady = true
                            echo 'â Health Check rÃ©ussi ! L\'application est joignable.'
                            break 
                        }
                    }
                    if (!isReady) {
                        echo 'â Health Check Ã©chouÃ©. RÃ©cupÃ©ration des logs du conteneur :'
                        sh "docker exec ansible-node1 docker logs shopping-cart"
                        error "Application unreachable after 100s"
                    }
                }
            }
        }
        stage('Metrics Check') {
            steps {
                script {
                    echo 'ð VÃ©rification des mÃ©triques Prometheus...'
                    def metricsStatus = sh(
                        script: "docker exec ansible-node1 curl -s -o /dev/null -w '%{http_code}' http://localhost:8071/prometheus || echo 'FAILED'",
                        returnStdout: true
                    ).trim()
                    echo "ð Code HTTP mÃ©triques : ${metricsStatus}"
                    if (metricsStatus != '200') {
                        echo "â ï¸ MÃ©triques non accessibles sur port 8071 (Code: ${metricsStatus}) - vÃ©rification sur port 8070..."
                        sh "docker exec ansible-node1 curl -s http://localhost:8070/prometheus || true"
                    } else {
                        echo 'â MÃ©triques Prometheus accessibles !'
                    }
                }
            }
        }
    }
    post {
        success {
            echo 'Pipeline Jenkins + Ansible terminÃ© avec succÃ¨s !'
        }
        failure {
            echo 'Pipeline Ã©chouÃ© !'
        }
        always {
            echo 'Pipeline terminÃ© !'
        }
    }
}
